#include <gccore.h>
#include <ogc/video.h>

int main() {
    void *frameBuffer = MEM_K0_TO_K1(SYS_GetArenaLo());
    VIDEO_Init();
    VIDEO_SetNextFramebuffer(frameBuffer);
    VIDEO_SetBlack(FALSE);
    VIDEO_Flush();
    while(1);
    return 0;
}

#define MODE3 0x0003
#define BG2_ENABLE 0x0400
#define REG_DISPCNT *(volatile unsigned short*)0x4000000
unsigned short* videoBuffer = (unsigned short*)0x6000000;

int main() {
    REG_DISPCNT = MODE3 | BG2_ENABLE;
    videoBuffer[120 + 160 * 80] = 0x7FFF; // Set white pixel at center
    while (1);
    return 0;
}

